entities.syntax:
typedef enum tagExtendedIsolationState {   extendedIsolationStateNoData = 0,
extendedIsolationStateTransition = 0x1,   extendedIsolationStateInfected = 0x2,
extendedIsolationStateUnknown = 0x3} ExtendedIsolationState;

typedef enum tagFailureCategory {
failureCategoryNone = 0,   failureCategoryOther = 1,
failureCategoryClientComponent = 2,
failureCategoryClientCommunication = 3,   failureCategoryServerComponent = 4,
failureCategoryServerCommunication = 5} FailureCategory;

typedef struct tagCorrelationId {   GUID     connId;
FILETIME timeStamp;} CorrelationId;
成员 connId
全局唯一标识符 (标识 SoH 交换的 GUID) 。 timeStamp
一个唯一 的 FILETIME 值，该值包含生成 SoHRequest 的系统时间。

typedef struct tagResultCodes {   UINT16  count;
HRESULT *results;} ResultCodes;
成员 count
结果代码数，表示介于 0 和 maxDwordCountPerSoHAttribute 之间的数字。 results
指向应用程序定义的 4-octet HRESULT 列表（指定客户端计算机是否合规）的指针，或指定 SoH 构造或处理错误原因的 NAP 错误常量列表。 值必须采用主机系统的字节顺序。
typedef struct tagSoH {   UINT16       count;

typedef enum tagFixupState {   fixupStateSuccess = 0,
fixupStateInProgress = 1,
fixupStateCouldNotUpdate = 2} FixupState;

typedef struct tagIpv4Address {
BYTE addr[4];} Ipv4Address;
成员 addr[4]
包含按网络字节顺序排列的 IPv4 网络地址的数组。

typedef struct tagIpv6Address {
BYTE addr[16];} Ipv6Address;
成员 addr[16]
包含按网络字节顺序排列的 IPv6 网络地址的数组。

typedef struct tagNetworkSoH {
UINT16 size;   BYTE   *data;
} NetworkSoH, NetworkSoHRequest, NetworkSoHResponse;
成员 size
范围 minNetworkSoHSize 到 maxNetworkSoHSize 的数据 Blob 的大小（以字节为单
位）。 data
指向包含 SoH 结构（按网络字节顺序排列）的数据 Blob 的指针。

typedef struct tagPrivateData {
UINT16 size;   BYTE   *data;} PrivateData;
成员 size
0 到 maxPrivateDataSize 范围内的数据的大小（以字节为单位）。 data
指向不透明数据 Blob 的指针。

typedef struct tagSoHAttribute {
UINT16 type;   UINT16 size;   BYTE   *value;} SoHAttribute;
成员 type
一个 SoHAttributeType 值，该值定义 value 中包含的属性类型。 size
值指向的 SoH 属性的大小（以字节为单位），其范围为 0 到 maxSoHAttributeSize。 value
指向 SoHAttributeValue 结构的指针，该结构包含 按类型定义的 SoH 属性值。
